import { execSync } from 'child_process';
import fs from 'fs';
const W='';
const FILES={'assets/pet-form.js':'','assets/account.css':''};
const V='add_action("wp_loaded",function(){if(!isset($_GET["ps_p1v"])||$_GET["ps_p1v"]!=="P1vx")return;$o=array();$dir=WP_PLUGIN_DIR."/petshop-core/";$fj=file_get_contents($dir."assets/pet-form.js");$cs=file_get_contents($dir."assets/account.css");$o["sha_js"]=substr(hash_file("sha256",$dir."assets/pet-form.js"),0,16);$o["sha_css"]=substr(hash_file("sha256",$dir."assets/account.css"),0,16);$o["progress_top"]=strpos($fj,"pspet-progress-top")!==false;$o["section_ico"]=strpos($fj,"pspet-section-ico")!==false;$o["span2"]=strpos($fj,"pspet-span2")!==false;$o["css_grid"]=strpos($cs,"grid-template-columns: 1fr 1fr")!==false;$o["css_cards"]=strpos($cs,"#FBF8F1")!==false;$o["css_chips"]=strpos($cs,"box-shadow: 0 3px 10px")!==false;header("Content-Type: application/json");echo json_encode($o);exit;});';
const TOKG=process.env.GH_TOKEN, REPO=process.env.GH_REPO||'raimis079-creator/petshop-bridge';
const U=process.env.WP_USER||'', P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const AUTH='-u "'+U+':'+P+'"';
function wj(m,path,body){fs.writeFileSync('/tmp/wb.json', JSON.stringify(body));
  return execSync('curl -sk '+AUTH+' -X '+m+' -H "Content-Type: application/json" --data-binary @/tmp/wb.json "https://dev.avesa.lt/wp-json/'+path+'"',{maxBuffer:50e6,timeout:70000}).toString();}
function putB64(name,b64){const u='https://api.github.com/repos/'+REPO+'/contents/screenshots/'+name;let s='';
 for(let i=0;i<5;i++){try{const j=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+TOKG+'" "'+u+'?n='+Math.random()+'"',{maxBuffer:50e6}).toString());if(j.sha)s=j.sha;}catch(e){}
  fs.writeFileSync('/tmp/pj.json',JSON.stringify({message:'r',content:b64,...(s?{sha:s}:{})}));
  const c=execSync('curl -s -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: Bearer '+TOKG+'" -d @/tmp/pj.json "'+u+'"',{maxBuffer:50e6}).toString().trim();
  if(c==='200'||c==='201')return c; execSync('sleep 2');}return 'fail';}
const o={};
try{
  const mk=wj('POST','code-snippets/v1/snippets',{name:'P1DEP (temp)',code:Buffer.from(W,'base64').toString('utf8'),scope:'front-end',active:true,priority:5});
  let sid=null; try{sid=JSON.parse(mk).id;}catch(e){}
  execSync('sleep 4');
  fs.writeFileSync('/tmp/payload.json', JSON.stringify({files:FILES}));
  for(let a=0;a<3;a++){ try{const r=execSync('curl -sk -X POST -H "Content-Type: application/json" --data-binary @/tmp/payload.json "https://dev.avesa.lt/?ps_dep218=Dp218x"',{maxBuffer:20e6,timeout:90000}).toString();
    const j=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1); o.write=j; if(j.includes('pet-form.js')&&j.includes('account.css')) break; }catch(e){o.write='ERR';} execSync('sleep 4'); }
  if(sid!==null){ try{wj('POST','code-snippets/v1/snippets/'+sid,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid+'"');}catch(e){} }
  const mk2=wj('POST','code-snippets/v1/snippets',{name:'P1VER (temp)',code:V,scope:'front-end',active:true,priority:5});
  let sid2=null; try{sid2=JSON.parse(mk2).id;}catch(e){}
  execSync('sleep 4');
  try{const r=execSync('curl -sk "https://dev.avesa.lt/?ps_p1v=P1vx"',{maxBuffer:5e6,timeout:60000}).toString();o.ver=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1).slice(0,500);}catch(e){o.ver='ERR';}
  if(sid2!==null){ try{wj('POST','code-snippets/v1/snippets/'+sid2,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid2+'"');}catch(e){} }
}catch(e){ o.err=String(e).slice(0,200); }
putB64('p1form.json', Buffer.from(JSON.stringify(o)).toString('base64'));
console.log('done');
